/**
 * Real attributedBody blobs extracted from chat.db for parser testing.
 * These are Apple typedstream (NSArchiver) encoded NSAttributedString objects.
 */

// Short message: "Y" (176 bytes, single char)
export const SHORT_MESSAGE = Buffer.from(
  '',
  'hex'
);
export const SHORT_MESSAGE_TEXT = 'Y';

// Medium message: "Ok, np, thanks for trying" (200 bytes)
export const MEDIUM_MESSAGE = Buffer.from(
  '',
  'hex'
);
export const MEDIUM_MESSAGE_TEXT = 'Ok, np, thanks for trying';

// Long message: 277 chars, uses 0x81 length encoding (504 bytes)
export const LONG_MESSAGE = Buffer.from(
  '',
  'hex'
);
export const LONG_MESSAGE_TEXT = 'I am ok with not having Charlie since he isn\u2019t part of the regular group.  With 5 there isn\u2019t enough hitting.  I can do 5 but it becomes more of a cardio workout rather than hitting a lot of balls.  If you want cardio I can run the heck out of you with 5.  Your call Jen.  ';

// Message with emoji: "Reacted 😒 to "No treats "" (207 bytes)
export const EMOJI_MESSAGE = Buffer.from(
  '',
  'hex'
);
export const EMOJI_MESSAGE_TEXT = 'Reacted \u{1F612} to \u201CNo treats \u201D';

// Malformed: not a typedstream at all
export const MALFORMED_BLOB = Buffer.from('deadbeefcafebabe', 'hex');

// Too small to be valid
export const TINY_BLOB = Buffer.from('040b', 'hex');
